# Category: insecure_jwt

import jwt
import base64
import datetime
import secrets

SECRET_KEY = secrets.token_hex(32)  # Generate a secret key (32 characters long)

def decode_and_verify_jwt(token):
    try:
        headers_and_claims = jwt.decode(token, SECRET_KEY, algorithms=['HS256'])
        print("Headers and Claims:", headers_and_claims)

        if 'exp' in headers_and_claims:
            expiration_time = headers_and_claims['exp']
            current_time = datetime.datetime.utcnow()

            if current_time > datetime.datetime.utcfromtimestamp(expiration_time):
                print("Token has expired.")
            else:
                print("Token is valid.")
    except jwt.ExpiredSignatureError as e:
        print(e)
    except jwt.InvalidTokenError as e:
        print(e)